# Now I have a clear picture. Let me run the full awk sweep
# The analysis covers 390 files with poll lines
# Key findings so far:
# - Only 2 actual "Build timeout after N polls" events in entire log history
# - Timeout 1: Inscribe, QUEUED all 120 polls (100% QUEUED, Q=120, died-while-QUEUED)  
# - Timeout 2: Vouch, 47 QUEUED + 3 WORKING before timeout (Q=47/50 = 94%, died-while-WORKING but Q≥25%)

# Now let me write the full awk analysis script
cat > /tmp/poll_analysis.awk << 'AWKEOF'
BEGIN {
    seq_count = 0
    file_count = 0
}

FNR == 1 {
    # New file - finalize previous sequences in this file
    if (current_file != "") {
        # finalize last sequence if any
        if (in_seq) {
            finalize_seq()
        }
    }
    current_file = FILENAME
    file_count++
    in_seq = 0
    prev_poll = 0
    prev_label = ""
}

{
    # Strip ANSI escape sequences
    line = $0
    gsub(/\x1b\[[0-9;]*m/, "", line)

    # Match poll lines: label: STATUS (poll N/MAX)
    if (match(line, /] ([a-z_]+ [A-Za-z+]+): (QUEUED|PENDING|WORKING|SUCCESS|FAILURE|TIMEOUT|CANCELLED|EXPIRED) \(poll ([0-9]+)\/([0-9]+)\)/, arr)) {
        label = arr[1]
        status = arr[2]
        poll_n = arr[3] + 0
        poll_max = arr[4] + 0

        # Detect new sequence: poll 1, or counter reset (went backwards)
        if (poll_n == 1 || (label == prev_label && poll_n < prev_poll)) {
            # Start new sequence
            if (in_seq) {
                finalize_seq()
            }
            seq_count++
            cur_label = label
            cur_max = poll_max
            cur_q = 0
            cur_first_working = 0
            cur_last_status = status
            cur_last_poll = poll_n
            in_seq = 1

            if (status == "QUEUED" || status == "PENDING") {
                cur_q++
            } else if (status == "WORKING" && cur_first_working == 0) {
                cur_first_working = poll_n
            }
        } else if (in_seq) {
            # Continue current sequence
            cur_last_status = status
            cur_last_poll = poll_n

            if (cur_first_working == 0) {
                if (status == "QUEUED" || status == "PENDING") {
                    cur_q++
                } else if (status == "WORKING") {
                    cur_first_working = poll_n
                }
            }
        }
        prev_poll = poll_n
        prev_label = label
    }

    # Match build timeout line
    if (match(line, /Build timeout after ([0-9]+) polls/, arr)) {
        if (in_seq) {
            cur_outcome = "TIMEOUT"
            finalize_seq()
            in_seq = 0
        }
    }
}

function finalize_seq() {
    # Determine outcome if not already set
    outcome = cur_outcome
    if (outcome == "") {
        if (cur_last_status == "SUCCESS") {
            outcome = "SUCCESS"
        } else if (cur_last_status == "FAILURE" || cur_last_status == "CANCELLED" || cur_last_status == "TIMEOUT" || cur_last_status == "EXPIRED") {
            outcome = "TERMINAL"
        } else {
            outcome = "TRUNCATED"
        }
    }
    cur_outcome = ""

    # Emit record
    print cur_label "\t" cur_max "\t" cur_q "\t" cur_last_status "\t" cur_last_poll "\t" outcome "\t" FILENAME
    in_seq = 0
    cur_label = ""
    cur_q = 0
    cur_first_working = 0
    cur_last_status = ""
    cur_last_poll = 0
}

END {
    if (in_seq) {
        finalize_seq()
    }
}
AWKEOF

