# Get per-label median Q for successful sequences
echo "=== PER-LABEL Q STATS (successful sequences only) ==="
awk -F'\t' '$6 == "SUCCESS" {print $1 "\t" $3}' /tmp/poll_results4.txt | sort > /tmp/q_by_label.txt

# For each label, compute median and p90
awk -F'\t' '{
  labels[$1] = 1
  n = ++count[$1]
  qvals[$1 "," n] = $2
}
END {
  for (label in labels) {
    n = count[label]
    # Sort qvals for this label
    for (i=1; i<=n; i++) {
      a[i] = qvals[label "," i]
    }
    # Bubble sort
    for (i=1; i<=n; i++) {
      for (j=i+1; j<=n; j++) {
        if (a[j] < a[i]) { t=a[i]; a[i]=a[j]; a[j]=t }
      }
    }
    if (n % 2 == 0) med = (a[n/2] + a[n/2+1]) / 2
    else med = a[int(n/2)+1]
    p90_idx = int(n * 0.9) + 1
    if (p90_idx > n) p90_idx = n
    printf "%s\tn=%d\tmedQ=%d\tp90Q=%d\tmaxQ=%d\n", label, n, med, a[p90_idx], a[n]
    delete a
  }
}' /tmp/q_by_label.txt | sort
